# Create a cost anomaly monitor for all AWS services
MONITOR_ARN=$(aws ce create-anomaly-monitor \
  --anomaly-monitor '{
    "MonitorName": "AllServicesMonitor",
    "MonitorType": "DIMENSIONAL",
    "MonitorDimension": "SERVICE"
  }' \
  --query 'MonitorArn' --output text)

# Create a subscription that alerts when anomaly exceeds $100 total impact
aws ce create-anomaly-subscription \
  --anomaly-subscription '{
    "SubscriptionName": "DailyAnomalyAlert",
    "MonitorArnList": ["'"$MONITOR_ARN"'"],
    "Subscribers": [{
      "Address": "cloud-finance@example.com",
      "Type": "EMAIL"
    }],
    "Threshold": 100,
    "Frequency": "DAILY"
  }'
